<?php
declare(strict_types=1);
require_once dirname(__DIR__).'/includes/cms.php';
$pdo=obtenerConexion();$id=cmsId($_GET['id']??0);$q=$pdo->prepare("SELECT s.*,a.nombre capacitacion,CONCAT_WS(' ',u.nombre,u.apellido) docente FROM capacitacion_secciones s JOIN asignaturas a ON a.id=s.asignatura_id JOIN usuarios u ON u.id=s.docente_id WHERE s.id=:id");$q->execute(['id'=>$id]);$seccion=$q->fetch();if(!$seccion){mostrarPaginaErrorAtenea(404);}
$q=$pdo->prepare("SELECT u.id,u.nombre,u.apellido,u.correo,i.id inscripcion_id,i.estado,i.assigned_at FROM inscripciones_capacitacion i JOIN usuarios u ON u.id=i.usuario_id WHERE i.seccion_id=:id AND i.estado IN('inscrito','finalizado') ORDER BY u.apellido,u.nombre");$q->execute(['id'=>$id]);$estudiantes=$q->fetchAll();
$q=$pdo->prepare("SELECT u.id,CONCAT_WS(' ',u.nombre,u.apellido) nombre FROM docentes_asignaturas da JOIN usuarios u ON u.id=da.docente_id WHERE da.asignatura_id=:a AND da.estado='activo' AND u.estado='activo' AND u.deleted_at IS NULL ORDER BY u.nombre,u.apellido");$q->execute(['a'=>$seccion['asignatura_id']]);$docentes=$q->fetchAll();
$q=$pdo->prepare("SELECT h.*,CONCAT_WS(' ',u.nombre,u.apellido) administrador FROM capacitacion_seccion_historial h LEFT JOIN usuarios u ON u.id=h.realizado_por WHERE h.seccion_id=:id ORDER BY h.id DESC LIMIT 100");$q->execute(['id'=>$id]);$historial=$q->fetchAll();
cmsCabecera('Detalle de sección','capacitaciones/secciones.php','Edita la sección, revisa estudiantes e inspecciona su historial.');
?>
<div class="d-flex flex-wrap gap-2 mb-4"><a class="btn btn-light" href="secciones.php?capacitacion_id=<?=$seccion['asignatura_id']?>">Volver a secciones</a><a class="btn btn-outline-primary" href="inscripciones.php?capacitacion_id=<?=$seccion['asignatura_id']?>&seccion_id=<?=$id?>">Gestionar asignaciones</a></div>
<div class="row g-4"><div class="col-xl-7"><section class="card card-rounded"><div class="card-body"><h2 class="h5"><?=atenea_e($seccion['codigo'].' · '.$seccion['capacitacion'])?></h2><form class="row g-3" method="post" action="seccion-accion.php" data-section-editor><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="editar"><input type="hidden" name="seccion_id" value="<?=$id?>"><input type="hidden" name="capacitacion_id" value="<?=$seccion['asignatura_id']?>"><div class="col-md-7"><label class="form-label">Nombre</label><input class="form-control" name="nombre" maxlength="180" value="<?=atenea_e($seccion['nombre'])?>" required></div><div class="col-md-5"><label class="form-label">Docente</label><select class="form-select" name="docente_id" required><?php foreach($docentes as$d):?><option value="<?=$d['id']?>" <?=$d['id']==$seccion['docente_id']?'selected':''?>><?=atenea_e($d['nombre'])?></option><?php endforeach;?></select></div><div class="col-md-4"><label class="form-label">Capacidad</label><input class="form-control" type="number" name="capacidad" min="1" max="30" value="<?=$seccion['capacidad_maxima']?>" data-current-students="<?=$seccion['cantidad_actual']?>" required><div class="form-text"><?=$seccion['cantidad_actual']?> estudiantes actuales.</div></div><div class="col-md-4"><label class="form-label">Estado</label><select class="form-select" name="estado"><?php foreach(['abierta','cerrada','finalizada','inactiva']as$v):?><option value="<?=$v?>" <?=$seccion['estado']===$v?'selected':''?>><?=ucfirst($v)?></option><?php endforeach;?></select></div><div class="col-md-4"><label class="form-label">Horario</label><input class="form-control" name="horario" maxlength="255" value="<?=atenea_e((string)$seccion['horario'])?>"></div><div class="col-md-6"><label class="form-label">Fecha de inicio</label><input class="form-control" type="date" name="fecha_inicio" value="<?=atenea_e((string)$seccion['fecha_inicio'])?>"></div><div class="col-md-6"><label class="form-label">Fecha final</label><input class="form-control" type="date" name="fecha_finalizacion" value="<?=atenea_e((string)$seccion['fecha_finalizacion'])?>"></div><div class="col-12"><div class="alert alert-warning" data-capacity-warning hidden>La nueva capacidad queda debajo del número actual. Los estudiantes permanecerán inscritos y no habrá nuevos cupos hasta regularizarla.</div><label class="form-label">Motivo del cambio</label><textarea class="form-control" name="motivo" maxlength="500" rows="3" required></textarea></div><div class="col-12"><button class="btn btn-primary">Guardar cambios</button></div></form></div></section></div><div class="col-xl-5"><section class="card card-rounded h-100"><div class="card-body"><h2 class="h5">Estudiantes asignados</h2><p><strong><?=$seccion['cantidad_actual']?></strong> inscritos · <strong><?=max(0,(int)$seccion['capacidad_maxima']-(int)$seccion['cantidad_actual'])?></strong> cupos disponibles</p><div class="list-group list-group-flush"><?php foreach($estudiantes as$e):?><div class="list-group-item px-0"><strong><?=atenea_e(trim($e['nombre'].' '.$e['apellido']))?></strong><small class="d-block text-muted"><?=atenea_e($e['correo'])?> · <?=atenea_e($e['estado'])?></small></div><?php endforeach;?><?php if(!$estudiantes):?><div class="text-center text-muted py-5">Todavía no hay estudiantes asignados.</div><?php endif;?></div></div></section></div></div>
<section class="card card-rounded mt-4"><div class="card-body"><h2 class="h5">Historial de cambios</h2><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Fecha</th><th>Acción</th><th>Motivo</th><th>Administrador</th></tr></thead><tbody><?php foreach($historial as$h):?><tr><td><?=date('d/m/Y H:i',strtotime($h['created_at']))?></td><td><?=atenea_e(ucfirst(str_replace('_',' ',$h['accion'])))?></td><td><?=atenea_e($h['motivo']?:'Sin detalle adicional')?></td><td><?=atenea_e($h['administrador']?:'Sistema automático')?></td></tr><?php endforeach;?><?php if(!$historial):?><tr><td colspan="4" class="text-center text-muted py-5">No hay cambios registrados todavía.</td></tr><?php endif;?></tbody></table></div></div></section>
<script>document.addEventListener('DOMContentLoaded',()=>{const input=document.querySelector('[data-current-students]'),warning=document.querySelector('[data-capacity-warning]');if(!input||!warning)return;const update=()=>warning.hidden=Number(input.value)>=Number(input.dataset.currentStudents);input.addEventListener('input',update);update()});</script>
